import{_ as s,o as a,c as e,al as l}from"./chunks/framework.BOATtE-F.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"prev":{"text":"API Reference","link":"/en/posts/docs/ageratum/07-api-reference"},"next":{"text":"Configuration","link":"/en/posts/docs/ageratum/09-config"}},"headers":[],"relativePath":"en/posts/docs/ageratum/08-architecture.md","filePath":"en/posts/docs/ageratum/08-architecture.md","lastUpdated":1774974346000}'),p={name:"en/posts/docs/ageratum/08-architecture.md"};function i(r,n,t,c,o,d){return a(),e("div",null,[...n[0]||(n[0]=[l(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to “Architecture”">​</a></h1><p>This document describes Ageratum&#39;s module layout, core data flows, and extension mechanisms, to help developers understand the codebase for maintenance and contribution.</p><hr><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to “High-Level Architecture”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Game Client                      │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  /ageratum command  ──→  AgeratumClient             │</span></span>
<span class="line"><span>│  Network packet (server) ──→  ClientPayloadHandler  │</span></span>
<span class="line"><span>│                          │                          │</span></span>
<span class="line"><span>│                          ▼                          │</span></span>
<span class="line"><span>│                    GuideScreen (GUI)                │</span></span>
<span class="line"><span>│                          │                          │</span></span>
<span class="line"><span>│              ┌───────────┴──────────────┐           │</span></span>
<span class="line"><span>│              ▼                          ▼           │</span></span>
<span class="line"><span>│    GuideDocumentCache            GuideDocumentLoader│</span></span>
<span class="line"><span>│    (pre-parsed cache)            (path utilities)   │</span></span>
<span class="line"><span>│              │                                      │</span></span>
<span class="line"><span>│              ▼                                      │</span></span>
<span class="line"><span>│       MarkdownParser                                │</span></span>
<span class="line"><span>│    (block-level + inline)                           │</span></span>
<span class="line"><span>│              │                                      │</span></span>
<span class="line"><span>│              ▼                                      │</span></span>
<span class="line"><span>│       MDComponent List                              │</span></span>
<span class="line"><span>│    ┌──────────────────────────┐                     │</span></span>
<span class="line"><span>│    │ MDTextComponent          │                     │</span></span>
<span class="line"><span>│    │ MDHeaderComponent        │                     │</span></span>
<span class="line"><span>│    │ MDCodeBlockComponent     │                     │</span></span>
<span class="line"><span>│    │ MDListComponent          │                     │</span></span>
<span class="line"><span>│    │ MDTableComponent         │                     │</span></span>
<span class="line"><span>│    │ MDQuoteComponent         │                     │</span></span>
<span class="line"><span>│    │ MDImageComponent         │                     │</span></span>
<span class="line"><span>│    │ MDNoticeBoxComponent     │                     │</span></span>
<span class="line"><span>│    │ MDRecipeComponent        │                     │</span></span>
<span class="line"><span>│    │ MDItemComponent          │                     │</span></span>
<span class="line"><span>│    │ MDNBTStructureComponent  │                     │</span></span>
<span class="line"><span>│    │ &lt;custom components&gt;      │                     │</span></span>
<span class="line"><span>│    └──────────────────────────┘                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  Network Layer (Bidirectional)       │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  OpenGuidePayload    (Server -&gt; Client)             │</span></span>
<span class="line"><span>│  ShareGuidePayload   (Client -&gt; Server)             │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ClientPayloadHandler / ServerPayloadHandler         │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              NeoForge Custom Registries              │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ageratum:extension_component_factory                │</span></span>
<span class="line"><span>│    → MDExtensionComponentFactory (block extensions)  │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ageratum:inline_component_factory                   │</span></span>
<span class="line"><span>│    → MDInlineComponentFactory (inline components)    │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ageratum:inline_style_parser                        │</span></span>
<span class="line"><span>│    → MDInlineStyleParser (inline styles)             │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ageratum:recipe_component_factory                   │</span></span>
<span class="line"><span>│    → MDRecipeComponent.RecipeComponentFactory        │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br></div></div><hr><h2 id="module-descriptions" tabindex="-1">Module Descriptions <a class="header-anchor" href="#module-descriptions" aria-label="Permalink to “Module Descriptions”">​</a></h2><h3 id="main-class-ageratum" tabindex="-1">Main Class (<code>Ageratum</code>) <a class="header-anchor" href="#main-class-ageratum" aria-label="Permalink to “Main Class (Ageratum)”">​</a></h3><ul><li>Declares <code>MOD_ID</code></li><li>Provides <code>location(path)</code> utility</li><li>Provides <code>openGuide(player, location)</code> server-side entry point</li></ul><h3 id="client-initialization-ageratumclient" tabindex="-1">Client Initialization (<code>AgeratumClient</code>) <a class="header-anchor" href="#client-initialization-ageratumclient" aria-label="Permalink to “Client Initialization (AgeratumClient)”">​</a></h3><ul><li>Registers NeoForge custom registries (<code>AgeratumRegistries.register()</code>)</li><li>Triggers class loading of built-in registrations (prevents JIT lazy-init from missing entries)</li><li>Registers the <code>/ageratum</code> client command</li><li>Registers the document pre-load reload listener (<code>RegisterClientReloadListenersEvent</code>)</li><li>Provides preview-mode entry (<code>/ageratum preview</code>) and file polling refresh</li></ul><h3 id="networking-and-collaboration-ageratumnetwork" tabindex="-1">Networking and Collaboration (<code>AgeratumNetwork</code>) <a class="header-anchor" href="#networking-and-collaboration-ageratumnetwork" aria-label="Permalink to “Networking and Collaboration (AgeratumNetwork)”">​</a></h3><ul><li><code>OpenGuidePayload</code>: server -&gt; client, asks client to open a guide</li><li><code>ShareGuidePayload</code>: client -&gt; server, requests broadcasting a share message</li><li><code>ServerPayloadHandler</code>: filters by <code>sameTeam</code> and sends clickable <code>/ageratum</code> commands</li></ul><h3 id="parsing-pipeline" tabindex="-1">Parsing Pipeline <a class="header-anchor" href="#parsing-pipeline" aria-label="Permalink to “Parsing Pipeline”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Raw .md file text</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  MarkdownParser.parseDocument()</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ Extract Front Matter (--- ... ---)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ Collect reference link definitions ([ref]: url)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ Block-level parsing (line-by-line scan)</span></span>
<span class="line"><span>        │   ├─ Code fence detection</span></span>
<span class="line"><span>        │   ├─ Extension syntax (::: and &lt;tag&gt;)</span></span>
<span class="line"><span>        │   ├─ Lists, blockquotes, tables</span></span>
<span class="line"><span>        │   ├─ Headings, horizontal rules</span></span>
<span class="line"><span>        │   ├─ Images</span></span>
<span class="line"><span>        │   └─ Paragraphs (default)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └─ MDDocument { frontMatter, components }</span></span>
<span class="line"><span>                │</span></span>
<span class="line"><span>                ▼</span></span>
<span class="line"><span>         Component list passed to GuideScreen for rendering</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="inline-parsing-mdcomponent-textformat" tabindex="-1">Inline Parsing (<code>MDComponent.textFormat()</code>) <a class="header-anchor" href="#inline-parsing-mdcomponent-textformat" aria-label="Permalink to “Inline Parsing (MDComponent.textFormat())”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Raw text</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Pre-process escape characters (\\* → %%MDESC42%%)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Expand reference links</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Extract code spans (\`code\`) to prevent inner content parsing</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Autolinks (&lt;url&gt;, &lt;email&gt;)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Standard links ([text](url))</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Bold / Italic / Strikethrough</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Custom inline styles</span></span>
<span class="line"><span>    │   (query INLINE_STYLE_PARSER_REGISTRY, sorted by priority)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ Restore escape characters</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>  FormattedText</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="cache-mechanism-guidedocumentcache" tabindex="-1">Cache Mechanism (<code>GuideDocumentCache</code>) <a class="header-anchor" href="#cache-mechanism-guidedocumentcache" aria-label="Permalink to “Cache Mechanism (GuideDocumentCache)”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Resource pack load/reload event</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  RELOAD_LISTENER.prepare()</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ Scan all ageratum/**/*.md files</span></span>
<span class="line"><span>        ├─ Parse each into MDDocument</span></span>
<span class="line"><span>        └─ Build NavigationTree (directory structure)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  RELOAD_LISTENER.apply()</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ Atomically replace PARSED_DOCUMENT_CACHE (volatile Map)</span></span>
<span class="line"><span>        └─ Atomically replace NAVIGATION_TREE_CACHE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>The cache uses <code>volatile</code> variables for thread visibility and <code>Map.copyOf()</code> for immutability.</p><hr><h2 id="extension-mechanisms" tabindex="-1">Extension Mechanisms <a class="header-anchor" href="#extension-mechanisms" aria-label="Permalink to “Extension Mechanisms”">​</a></h2><h3 id="extension-component-registration-flow" tabindex="-1">Extension Component Registration Flow <a class="header-anchor" href="#extension-component-registration-flow" aria-label="Permalink to “Extension Component Registration Flow”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>External mod registers</span></span>
<span class="line"><span>DeferredRegister&lt;MDExtensionComponentFactory&gt;</span></span>
<span class="line"><span>        │  .register(modEventBus)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>NeoForge registration event</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>AgeratumRegistries.EXTENSION_COMPONENT_FACTORY_REGISTRY</span></span>
<span class="line"><span>        │  lookup by ResourceLocation (namespace:name)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>MarkdownParser encounters extension syntax</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>MDExtensionComponentFactory.create(context)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Returns MDComponent → added to document component list</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><h3 id="inline-style-resolution-flow" tabindex="-1">Inline Style Resolution Flow <a class="header-anchor" href="#inline-style-resolution-flow" aria-label="Permalink to “Inline Style Resolution Flow”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MDComponent.textFormat(rawText)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Query AgeratumRegistries.INLINE_STYLE_PARSER_REGISTRY</span></span>
<span class="line"><span>(all registered parsers, sorted by priority ascending)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Scan text character by character:</span></span>
<span class="line"><span>  for each parser (ascending priority):</span></span>
<span class="line"><span>    parser.parse(text, pos) → InlineStyleMatch or null</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Take the earliest match (smallest startPos);</span></span>
<span class="line"><span>if tie on position, take the lowest priority value</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Apply Style to matched range, recursively process inner text</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Output FormattedText</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h3 id="inline-component-resolution-flow" tabindex="-1">Inline Component Resolution Flow <a class="header-anchor" href="#inline-component-resolution-flow" aria-label="Permalink to “Inline Component Resolution Flow”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>MDComponent.textFormat(rawText)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Query AgeratumRegistries.INLINE_COMPONENT_FACTORY_REGISTRY</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Match self-closing inline tag: &lt;namespace:id .../&gt;</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Build MDInlineComponentContext</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>MDInlineComponentFactory.create(context)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Append returned FormattedText to the current inline output</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><hr><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to “Design Principles”">​</a></h2><h3 id="_1-separation-of-concerns-soc" tabindex="-1">1. Separation of Concerns (SoC) <a class="header-anchor" href="#_1-separation-of-concerns-soc" aria-label="Permalink to “1. Separation of Concerns (SoC)”">​</a></h3><p>Each class has a single responsibility:</p><ul><li><code>MarkdownParser</code>: text → component list only</li><li><code>GuideDocumentLoader</code>: path normalization and IO only</li><li><code>GuideDocumentCache</code>: preload cache management only</li><li><code>GuideScreen</code>: GUI rendering and user interaction only</li></ul><h3 id="_2-client-side-isolation-mod-dist-dist-client" tabindex="-1">2. Client-Side Isolation (<code>@Mod(dist = Dist.CLIENT)</code>) <a class="header-anchor" href="#_2-client-side-isolation-mod-dist-dist-client" aria-label="Permalink to “2. Client-Side Isolation (@Mod(dist = Dist.CLIENT))”">​</a></h3><p>All rendering-related code (GUI, Markdown parsing, registries) is isolated to the client side via <code>@Mod(dist = Dist.CLIENT)</code>. The server side holds only <code>Ageratum</code> (no render code) and <code>AgeratumNetwork</code>.</p><h3 id="_3-registry-driven-extension" tabindex="-1">3. Registry-Driven Extension <a class="header-anchor" href="#_3-registry-driven-extension" aria-label="Permalink to “3. Registry-Driven Extension”">​</a></h3><p>All extension points are implemented via NeoForge Custom Registries, not reflection or interface scanning. Benefits:</p><ul><li>Registration lifecycle aligns with the game (frozen after <code>FMLCommonSetupEvent</code>)</li><li>Supports <code>DeferredHolder</code> lazy references</li><li>Automatic conflict detection for duplicate keys</li></ul><h3 id="_4-preload-cache" tabindex="-1">4. Preload + Cache <a class="header-anchor" href="#_4-preload-cache" aria-label="Permalink to “4. Preload + Cache”">​</a></h3><p>All documents are parsed once on resource pack load and cached. This eliminates IO and parsing overhead on every document open. The cache is invalidated and rebuilt automatically on resource pack reload.</p><h3 id="_5-language-fallback" tabindex="-1">5. Language Fallback <a class="header-anchor" href="#_5-language-fallback" aria-label="Permalink to “5. Language Fallback”">​</a></h3><p>When looking up documents, Ageratum first tries the client&#39;s current language (e.g. <code>zh_cn</code>), then falls back to <code>en_us</code> if not found. This simplifies mod development: <strong>providing only the <code>en_us</code> version is sufficient</strong> for all language clients.</p><h3 id="_6-preview-isolation" tabindex="-1">6. Preview Isolation <a class="header-anchor" href="#_6-preview-isolation" aria-label="Permalink to “6. Preview Isolation”">​</a></h3><p>Preview documents use a dedicated namespace <code>ageratum_review</code> and are read from local <code>previewPath</code> instead of resource-pack caches, avoiding pollution of normal guide indexing.</p><hr><h2 id="file-size-guidelines" tabindex="-1">File Size Guidelines <a class="header-anchor" href="#file-size-guidelines" aria-label="Permalink to “File Size Guidelines”">​</a></h2><p>The project follows a &quot;no oversized files&quot; policy:</p><table tabindex="0"><thead><tr><th>File Type</th><th>Line Limit</th><th>Policy</th></tr></thead><tbody><tr><td>Single Java class</td><td>~400 lines</td><td>Split if exceeded</td></tr><tr><td>Inner classes</td><td>Extracted to separate files</td><td></td></tr><tr><td>Static utility methods</td><td>Moved to dedicated utility class</td><td></td></tr></tbody></table><hr><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to “Testing Strategy”">​</a></h2><p>The current version has no unit tests. Functionality is verified through in-game testing (<code>/ageratum</code> command + resource packs).</p><p>Planned future additions:</p><ul><li>Unit tests for <code>MarkdownParser</code> text output (game-environment-independent)</li><li>Path normalization tests for <code>GuideDocumentLoader</code></li></ul><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to “See Also”">​</a></h2><ul><li><a href="./07-api-reference.html">API Reference</a></li><li><a href="./04-extension-components.html">Extension Components</a></li><li><a href="./05-inline-style-parsers.html">Inline Style Parsers</a></li><li><a href="./10-preview-and-sharing.html">Preview and Sharing</a></li></ul>`,56)])])}const m=s(p,[["render",i]]);export{u as __pageData,m as default};
